svg.script:
setTimeout(function() {
  var svg    = document.documentElement;
  var rectEl = svg.querySelector("rect[id]");
  var textEl = svg.querySelector("text[id]");

  if (!rectEl || !textEl) return;

  var rX     = parseFloat(rectEl.getAttribute("x"));
  var rW     = parseFloat(rectEl.getAttribute("width"));
  var rY     = parseFloat(rectEl.getAttribute("y"));
  var rH     = parseFloat(rectEl.getAttribute("height"));
  var pad    = 10;
  var anchor = textEl.getAttribute("text-anchor") || "start";

  if (anchor === "start") {
    textEl.setAttribute("x", rX + pad);
  } else if (anchor === "end") {
    textEl.setAttribute("x", rX + rW - pad);
  } else {
    textEl.setAttribute("x", rX + rW / 2);
  }

  textEl.setAttribute("y", rY + rH / 2);
}, 0);
